#include <stdio.h>
#include <string.h>
void gogo(char a[], int j, int s, int r)
{
    for (int k = 0; k < r; k++)
        for (int i = j; i < s; i++)
        {
            a[i] = a[i + 1];
        }
}
int main(void)
{
    int s, counts = 0;
    char a[105] = {0};
    scanf("%d", &s);
    for (int i = 0; i < s; i++)
    {
        scanf(" %c", &a[i]);
    }
    for (int i = 'z'; i >= 'a'; i--)
    {
        for (int j = 0; j < strlen(a); j++)
        {
            int num = 0;
            if (a[j] == i)
            {
                if (a[j - 1] == i + 1)
                {
                    for (int k = j - 1; k >= 0; k--)
                    {
                        if (a[k] == a[j - 1])
                        {
                            num++;
                        }
                        else
                            break;
                    }
                    gogo(a, j - num, strlen(a), num);
                    counts += num;
                    if (num != 0)
                    {
                        j = 0;
                        num = 0;
                    }
                }
                if (a[j + 1] == i + 1)
                {
                    for (int k = j + 1; k < strlen(a); k++)
                    {
                        if (a[k] == a[j + 1])
                        {
                            num++;
                        }
                        else
                            break;
                    }
                    gogo(a, j + 1, strlen(a), num);
                    counts += num;
                    if (num != 0)
                    {
                        j = 0;
                        num = 0;
                    }
                }
            }
        }
    }
    printf("%d\n", counts);
}

